#!/usr/bin/env node
// A5 J6 suite — calibration + THE PROOF (spec §14-A5 + §7(a)):
//
//   node scripts/test-judge-calibration.mjs
//
//  1. CORPUS INTEGRITY — scripts/data/judge-calib-corpus.jsonl (generated by
//     scripts/gen-cheater-corpus.mjs): uniform judge-config stamp at the
//     CURRENT PARAMS_A5 tier-1 values, canonical Tier1Records (params pin,
//     ladder, internal consistency), all four families present.
//  2. MEASURED ANCHORS ROUND-TRIP — judge/anchors.ts TIER2_ANCHORS_JUDGE is
//     recomputed here from the honest rows (per-band means, weighted-PAV
//     monotonization, residual σ through the EXACT tier1/tier2 floor-division
//     interpolation) and must match integer-for-integer. σ_acpl of the J3
//     review-math fit is cross-checked against this corpus (report line).
//  3. HONEST HOLDOUT NEVER FLAGGED — all honest sides partitioned into
//     K-game windows: ZERO convictions AND ZERO escalations; the trailing-K
//     escalationDue scan over the full honest stream never fires. Max honest
//     z + margin to zEscalateMicro is printed (the §14-A5 evidence). A
//     split-half check (anchors refit on even games, scan on odd games)
//     guards the in-sample bias of the committed anchors. A LONGITUDINAL
//     single-account holdout (A5-09) then assembles ONE honest account's
//     trailing-K temporal stream from the committed top-band sides with a
//     lagging display rating + fold RD, and asserts the deterministic
//     escalationDue trigger never fires under the A5-02 RD-aware scoring
//     though it WOULD at the lagging point estimate (the production geometry
//     the cross-sectional scan cannot exhibit).
//  4. CHEATERS CONVICTED WITHIN ONE K-WINDOW — the FULL and HALF families'
//     windows convict (z ≥ zThresholdMicro); games-to-conviction (earliest
//     prefix whose aggregate convicts) is printed per family. The
//     deterministic trigger (escalationDue) fires inside the window.
//  5. THRESHOLD-ε — the metered bot (assistance solved against the measured
//     baseline to target z ≈ 2.6 < zEscalateMicro) lands escalate-not-convict
//     or below: z < zThresholdMicro asserted, position vs the escalation
//     frontier printed.
//  5b. J7 CROSS-WINDOW LIFETIME ACCUMULATION — the §7(a) closure proof over
//     the extended thresh family (≥ 120 metered games, ≥ 4 closed K-windows,
//     corpus append order = the synthetic ladder's chain order): no single
//     window ever convicts, most stay sub-escalation, BUT lifetimeVerdict
//     escalates within a few windows and CONVICTS at the realized crossing
//     (reported; the metering targets 2.6σ/window with sampling noise, so
//     crossings land where the realized mean lands them). The honest holdout
//     partitioned the same way is the false-positive guard: its lifetime z
//     stays under 2σ at EVERY W (trajectory + margin printed) — if this
//     assertion ever trips, STOP and report to the lead; do not tune.
//  6. EMPTY-MARGIN QUANTIFICATION (§7a) — the threshold-ε bot's games are
//     folded through the deterministic Glicko core (ratings/glicko.ts, the
//     a4-v1 fold's exact update) from a settled true-strength state (1500,
//     RD 60) against its real opponents; expected rating gain per game at
//     max-undetectable assistance is printed and sanity-bounded. This is the
//     §7(a) calibration number: the margin between undetectable and
//     advantageous.
//  7. RECEIPT (engine, LOCAL-ONLY — test-judge-node convention): one stored
//     game is re-judged through the pinned-WASM Node adapter at the true
//     Tier-1 config and must rebuild the byte-identical Tier1Record.
//
//  Engine-free deterministic receipts also fold into the run: A5-27 pins the
//  judged-bits param projection to a frozen golden (a judged-surface param
//  change fails CI even if every corpus stamp is migrated in place); A5-28
//  asserts sidesOf() is a strict TOTAL order (window/fold determinism on every
//  JS engine); A5-29 runs the canonical transcriptToJudgePositions builder over
//  EVERY corpus row of every family (cross-producer surface/encoding divergence
//  is caught under CI, not only by the one local engine re-judge).
//
// Style: failures counter, section banners, per-assert one-line, exit(failures?1:0).

import { build } from 'esbuild'
import { pathToFileURL, fileURLToPath } from 'node:url'
import { dirname, resolve } from 'node:path'
import { existsSync, mkdirSync, mkdtempSync, readFileSync, rmSync, writeFileSync } from 'node:fs'

const __dirname = dirname(fileURLToPath(import.meta.url))
const ROOT = resolve(__dirname, '..')
const CORPUS = resolve(ROOT, 'scripts/data/judge-calib-corpus.jsonl')
const ENGINE_JS = resolve(ROOT, 'node_modules/stockfish/bin/stockfish-18-lite-single.js')
const ENGINE_WASM = resolve(ROOT, 'node_modules/stockfish/bin/stockfish-18-lite-single.wasm')

let passed = 0
let failures = 0
function ok(cond, msg) {
  if (cond) {
    passed++
    console.log(`  ✓ ${msg}`)
  } else {
    failures++
    console.log(`  ✗ ${msg}`)
  }
}
function eq(a, b, msg) {
  ok(a === b, a === b ? msg : `${msg} (got ${JSON.stringify(a)}, want ${JSON.stringify(b)})`)
}
function section(t) {
  console.log(`\n── ${t} ${'─'.repeat(Math.max(0, 66 - t.length))}`)
}

// ---- bundle the judge barrel + glicko + node adapter ------------------------
const cacheRoot = resolve(ROOT, 'node_modules/.cache/judge-calibration-test')
mkdirSync(cacheRoot, { recursive: true })
const outdir = mkdtempSync(resolve(cacheRoot, 'run-'))
let M
try {
  const SRC = resolve(ROOT, 'src/shared/accounts').replace(/\\/g, '/')
  const entry = resolve(outdir, 'entry.ts')
  writeFileSync(
    entry,
    [
      `export * from '${SRC}/judge/index.ts'`,
      `export * as glicko from '${SRC}/ratings/glicko.ts'`,
      `export * as adapter from '${resolve(ROOT, 'server/judge/nodeAdapter.ts').replace(/\\/g, '/')}'`,
    ].join('\n'),
  )
  const outfile = resolve(outdir, 'calib.mjs')
  await build({
    entryPoints: [entry],
    outfile,
    bundle: true,
    format: 'esm',
    platform: 'node',
    mainFields: ['module', 'main'],
    conditions: ['import', 'module', 'default'],
    alias: { '@shared': resolve(ROOT, 'src/shared') },
    absWorkingDir: ROOT,
    logLevel: 'warning',
  })
  M = await import(pathToFileURL(outfile).href)
} finally {
  rmSync(outdir, { recursive: true, force: true })
}
const J = M
const K = J.PARAMS_A5.reganK
const A = J.TIER2_ANCHORS_JUDGE

// ---- corpus ----------------------------------------------------------------
section('corpus integrity (judge-calib-corpus.jsonl)')
ok(existsSync(CORPUS), 'scripts/data/judge-calib-corpus.jsonl exists')
const rows = readFileSync(CORPUS, 'utf8')
  .split('\n')
  .filter(Boolean)
  .map((l) => JSON.parse(l))
const fam = (f) => rows.filter((r) => r.family === f)
const uniq = (f) => new Set(rows.map(f))
console.log(`  · ${rows.length} game rows: honest ${fam('honest').length}, full ${fam('full').length}, half ${fam('half').length}, thresh ${fam('thresh').length}`)
ok(fam('honest').length >= 100, `honest family carries ≥ 100 games (${fam('honest').length})`)
ok(fam('full').length >= 25, `full family carries ≥ 25 games (${fam('full').length})`)
ok(fam('half').length >= 25, `half family carries ≥ 25 games (${fam('half').length})`)
ok(fam('thresh').length >= 25, `thresh family carries ≥ 25 games (${fam('thresh').length})`)
ok(
  fam('thresh').length >= 120,
  `J7: thresh family extended to ≥ 120 metered games / ≥ 4 closed K-windows (${fam('thresh').length})`,
)
eq(
  new Set(fam('thresh').map((r) => r.assistProbMicro)).size,
  1,
  'J7: thresh metering uniform across append runs (one assistProbMicro)',
)
eq(uniq((r) => r.judgeNodes).size, 1, 'judgeNodes uniform')
eq(uniq((r) => r.judgeMultiPv).size, 1, 'judgeMultiPv uniform')
eq(uniq((r) => r.judgeParams).size, 1, 'judgeParams uniform')
eq([...uniq((r) => r.judgeNodes)][0], J.PARAMS_A5.t1Nodes, 'corpus judged at PARAMS_A5.t1Nodes')
eq([...uniq((r) => r.judgeMultiPv)][0], J.PARAMS_A5.t1MultiPv, 'corpus judged at PARAMS_A5.t1MultiPv')
eq([...uniq((r) => r.judgeParams)][0], J.PARAMS_A5_DIGEST, 'corpus params digest == CURRENT PARAMS_A5_DIGEST (drift ⇒ regenerate)')
ok(
  rows.every((r) => r.v === 1 && r.rec?.v === 1 && r.rec.params === J.PARAMS_A5_DIGEST && r.rec.ladder === 'calib'),
  'every Tier1Record pins PARAMS_A5_DIGEST on ladder calib',
)
// ── A5-27: the corpus↔params linkage must NOT be satisfiable by editing a
// per-row JSONL stamp. r.judgeParams / rec.params are rewritable fields (they
// were migrated IN PLACE at the J7 digest drift), so `stamp == PARAMS_A5_DIGEST`
// proves only that someone re-stamped — not that the bits were produced under
// the current judged-surface rules. The bit-level proof of THAT is the local
// engine receipt (§7), skipped under CI. So here the JUDGED-BITS PARAM
// PROJECTION — the ONLY inputs that move the engine's output bits and the
// score-equivalence match count — is pinned against a FROZEN golden read from
// LIVE PARAMS_A5, INDEPENDENT of any corpus field. A judged-bits change
// (t1Nodes, t1MultiPv, hashMb, scoreEquivCp, ttReset) trips this in CI even if
// every judgeParams stamp is migrated in place, because the check reads
// PARAMS_A5, not the JSONL; only a deliberate edit to THIS literal — sitting
// next to "drift ⇒ regenerate" — can green it. Tier-2 aggregation params
// (lifetimeScheme, the ACTUAL J7 drift) are EXCLUDED, so legitimate Tier-2
// evolution never drifts this golden and never tempts a stamp migration.
const JUDGED_BITS_GOLDEN = { t1Nodes: 200_000, t1MultiPv: 4, hashMb: 16, scoreEquivCp: 15, ttReset: 'per-game' }
for (const k of Object.keys(JUDGED_BITS_GOLDEN)) {
  eq(
    J.PARAMS_A5[k],
    JUDGED_BITS_GOLDEN[k],
    `A5-27 judged-bits golden: PARAMS_A5.${k} == ${JSON.stringify(JUDGED_BITS_GOLDEN[k])} (judged-surface change ⇒ REGENERATE the corpus + re-freeze here, never migrate stamps)`,
  )
}
// Cross-bind the corpus's OWN per-row judged-surface stamps to those frozen
// values (nodes/multiPv are stamped; hashMb/scoreEquivCp/ttReset ride only in
// the digest): a row judged at a different budget cannot slip in behind a
// migrated digest string.
ok(
  rows.every((r) => r.judgeNodes === JUDGED_BITS_GOLDEN.t1Nodes && r.judgeMultiPv === JUDGED_BITS_GOLDEN.t1MultiPv),
  'A5-27: every corpus row stamps the FROZEN judged-bits node/multiPv budget (not merely a matching digest string)',
)
ok(
  rows.every((r) => r.moves.length === r.nPlies && r.fens.length === r.nPlies && r.rec.game === r.gameKey),
  'moves/fens lengths and record game keys are consistent',
)
ok(
  rows.every((r) =>
    ['w', 'b'].every((c) => {
      const s = r.rec[c]
      return (
        s.scored >= 0 &&
        s.matched <= s.scored &&
        s.matchMicro === (s.scored === 0 ? 0 : Math.floor((s.matched * 1_000_000) / s.scored)) &&
        s.acplMicro >= 0 &&
        s.acplMicro <= 2_000_000_000
      )
    }),
  ),
  'per-side signals internally consistent (matchMicro = floor(1e6·matched/scored), ranges hold)',
)
ok(
  rows.every((r) => (r.family === 'honest' ? r.subject === null : r.subject === 'w' || r.subject === 'b')),
  'subject side present for cheater families, null for honest',
)
ok(
  rows.every((r) => r.family === 'honest' || r.assistPlan.every((p) => {
    // every assisted ply belongs to the subject (subject moves on even plies iff subject is white)
    return (p % 2 === 0) === (r.subject === 'w')
  })),
  'assisted plies all belong to the subject side',
)

// ---- shared derivations ------------------------------------------------------
// A5-28: a TOTAL, tie-broken ordering for side rows so §5 threshold-ε window
// selection and the §7(a) glicko fold order are spec-deterministic on EVERY
// conforming JS engine, not V8-TimSort-defined. The prior tail
// `a.side < b.side ? -1 : 1` returned +1 (never 0) on a FULL (idx,side) tie, so
// cmp(a,b)===cmp(b,a)===1 — an INCONSISTENT comparator (ECMA-262 leaves such
// sorts implementation-defined). The thresh family is three APPEND runs
// (mruav11j / j7w1 / j7w2) whose subject side follows the same i%2 rule, so ~90
// (idx,side) pairs collide. The globally-unique gameKey is a total tiebreak
// (one subject row per gameKey; the two honest colors already differ on `side`,
// so honest/full/half ordering is byte-identical to before — only the genuinely
// tied thresh rows become deterministic). idx and side branches are unchanged,
// so this ONLY resolves the previously-undefined ties.
function sideCmp(a, b) {
  if (a.idx !== b.idx) return a.idx - b.idx
  if (a.side !== b.side) return a.side < b.side ? -1 : 1
  return a.r.gameKey < b.r.gameKey ? -1 : a.r.gameKey > b.r.gameKey ? 1 : 0
}

/** Per-subject-side stat rows (elo, signals, ordering key). */
function sidesOf(family) {
  const out = []
  for (const r of rows) {
    if (r.family !== family) continue
    const idx = Number(r.gameKey.slice(r.gameKey.lastIndexOf('-') + 1))
    if (family === 'honest') {
      for (const c of ['w', 'b']) {
        if (r.rec[c].scored >= 1)
          out.push({ elo: c === 'w' ? r.whiteElo : r.blackElo, rec: r.rec, side: c, idx, r })
      }
    } else if (r.rec[r.subject].scored >= 1) {
      out.push({ elo: r.subject === 'w' ? r.whiteElo : r.blackElo, rec: r.rec, side: r.subject, idx, r })
    }
  }
  // A5-28: strict TOTAL order — schedule index, then side (b<w), then the
  // globally-unique gameKey tiebreak (deterministic on every JS engine).
  out.sort(sideCmp)
  return out
}
const honestSides = sidesOf('honest')
const mean = (xs) => xs.reduce((a, b) => a + b, 0) / xs.length
const std = (xs) => {
  const m = mean(xs)
  return Math.sqrt(xs.reduce((a, x) => a + (x - m) * (x - m), 0) / xs.length)
}

/** Weighted PAV isotonic regression — the EXACT pooling gen/anchors used.
 * dir −1: nonincreasing (acpl); +1: nondecreasing (match). */
function pav(values, weights, dir) {
  const blocks = values.map((v, i) => ({ v, w: weights[i], idx: [i] }))
  let changed = true
  while (changed) {
    changed = false
    for (let i = 0; i + 1 < blocks.length; i++) {
      const a = blocks[i]
      const b = blocks[i + 1]
      if (dir < 0 ? b.v > a.v : b.v < a.v) {
        blocks.splice(i, 2, { v: (a.v * a.w + b.v * b.w) / (a.w + b.w), w: a.w + b.w, idx: [...a.idx, ...b.idx] })
        changed = true
        break
      }
    }
  }
  const out = new Array(values.length)
  for (const bl of blocks) for (const i of bl.idx) out[i] = bl.v
  return out
}

function fitAnchors(sides) {
  const bands = [...new Set(sides.map((s) => s.elo))].sort((a, b) => a - b)
  const byBand = new Map(bands.map((e) => [e, sides.filter((s) => s.elo === e)]))
  const ns = bands.map((e) => byBand.get(e).length)
  const acplPav = pav(bands.map((e) => mean(byBand.get(e).map((s) => s.rec[s.side].acplMicro))), ns, -1)
  const matchPav = pav(bands.map((e) => mean(byBand.get(e).map((s) => s.rec[s.side].matchMicro))), ns, +1)
  const acplByElo = bands.map((e, i) => ({ elo: e, acplMicro: Math.round(acplPav[i]) }))
  const matchByElo = bands.map((e, i) => ({ elo: e, matchMicro: Math.round(matchPav[i]) }))
  const acplAnchors = { v: 1, nodes: J.PARAMS_A5.t1Nodes, multiPv: J.PARAMS_A5.t1MultiPv, acplByElo, sigmaAcplMicro: 1, fit: 'tmp' }
  const bundle = { v: 1, acpl: acplAnchors, matchByElo, sigmaMatchMicro: 1, fit: 'tmp' }
  const sigmaAcplMicro = Math.round(
    std(sides.map((s) => s.rec[s.side].acplMicro - J.expectedAcplMicro(acplAnchors, s.elo))),
  )
  const sigmaMatchMicro = Math.round(
    std(sides.map((s) => s.rec[s.side].matchMicro - J.expectedMatchMicro(bundle, s.elo))),
  )
  acplAnchors.sigmaAcplMicro = sigmaAcplMicro
  bundle.sigmaMatchMicro = sigmaMatchMicro
  return bundle
}

// ---- A5-28: sidesOf() is a spec-deterministic strict TOTAL order -------------
section('ordering determinism: sidesOf() is a strict total order (A5-28)')
for (const family of ['honest', 'full', 'half', 'thresh']) {
  const s = sidesOf(family)
  let strict = s.length > 0
  let tieAt = -1
  for (let i = 1; i < s.length; i++) {
    if (sideCmp(s[i - 1], s[i]) >= 0) {
      strict = false
      tieAt = i
      break
    }
  }
  ok(
    strict,
    `sidesOf('${family}'): strict total order over ${s.length} rows — comparator never 0-ties two distinct rows` +
      (tieAt >= 0 ? ` (equal-compare at ${tieAt})` : ''),
  )
}
{
  // The gameKey tiebreak is LOAD-BEARING: the thresh family genuinely carries
  // full (idx,side) collisions across its three append runs — without a total
  // tertiary key the sort would be implementation-defined on exactly these, so
  // the §5 window and §7(a) fold would depend on the host engine's sort.
  const t = sidesOf('thresh')
  const idxSide = new Set(t.map((s) => `${s.idx}|${s.side}`))
  const ties = t.length - idxSide.size
  ok(
    ties > 0,
    `thresh carries ${ties} genuine (idx,side) collisions across its append runs — the gameKey tertiary key is load-bearing (not vacuous)`,
  )
}

// ---- 2. measured anchors round-trip -----------------------------------------
section('measured anchors: TIER2_ANCHORS_JUDGE round-trips the corpus')
const refit = fitAnchors(honestSides)
ok(A && A.v === 1, 'TIER2_ANCHORS_JUDGE loads from the judge barrel')
eq(A.acpl.nodes, J.PARAMS_A5.t1Nodes, 'anchors acpl set targets t1Nodes')
eq(A.acpl.multiPv, J.PARAMS_A5.t1MultiPv, 'anchors acpl set targets t1MultiPv')
ok(!A.fit.includes('PENDING') && A.fit.includes('judge-calib-corpus'), 'fit tag names the calibration corpus (not a placeholder)')
// The fit tag pins the params digest AT FIT TIME (J6). J7's PARAMS_A5 change
// (lifetimeScheme — Tier-2 aggregation only) drifted the full rule-set digest
// without touching any judged-bits input (t1Nodes/t1MultiPv/hashMb/
// scoreEquivCp unchanged); the corpus stamps were migrated to the CURRENT
// digest on that basis, and the engine receipt below re-proves a pre-J7 row
// reproduces bit-for-bit under it. The corpus↔current linkage is asserted in
// section 1 (uniform stamp == PARAMS_A5_DIGEST); here the anchors artifact
// pins its own fit-time lineage (anchors.ts JUDGE_ANCHORS_PARAMS_DIGEST).
ok(A.fit.includes(J.JUDGE_ANCHORS_PARAMS_DIGEST), 'fit tag pins the fit-time params digest (JUDGE_ANCHORS_PARAMS_DIGEST)')
eq(
  JSON.stringify(A.acpl.acplByElo),
  JSON.stringify(refit.acpl.acplByElo),
  'acplByElo knots == recomputed per-band PAV means (integer-exact)',
)
eq(
  JSON.stringify(A.matchByElo),
  JSON.stringify(refit.matchByElo),
  'matchByElo knots == recomputed per-band PAV means (integer-exact)',
)
eq(A.acpl.sigmaAcplMicro, refit.acpl.sigmaAcplMicro, `sigmaAcplMicro == recomputed residual std (${refit.acpl.sigmaAcplMicro})`)
eq(A.sigmaMatchMicro, refit.sigmaMatchMicro, `sigmaMatchMicro == recomputed residual std (${refit.sigmaMatchMicro})`)
ok(
  A.matchByElo.every((k, i, a) => i === 0 || k.matchMicro >= a[i - 1].matchMicro),
  'match curve nondecreasing in elo (PAV held)',
)
ok(
  A.acpl.acplByElo.every((k, i, a) => i === 0 || k.acplMicro <= a[i - 1].acplMicro),
  'acpl curve nonincreasing in elo (PAV held)',
)
{
  // J3 (review-math) σ cross-check — report, sanity-bound only.
  const j3 = J.TIER1_ANCHORS_JUDGE
  const resid = honestSides.map((s) => s.rec[s.side].acplMicro - J.expectedAcplMicro(j3, s.elo))
  const sigma = std(resid)
  console.log(
    `  · J3 cross-check: this corpus vs TIER1_ANCHORS_JUDGE curve — bias ${(mean(resid) / 1e6).toFixed(2)}cp, ` +
      `resid σ ${(sigma / 1e6).toFixed(2)}cp (J3 measured 21.90cp on the review-math statistic)`,
  )
  ok(sigma > 10e6 && sigma < 40e6, 'J3-curve residual σ on this corpus is in the same regime (10..40cp)')
}

// ---- 3. honest holdout --------------------------------------------------------
section(`honest holdout: ${honestSides.length} sides, zero flags`)
const entryOf = (s) => ({ rec: s.rec, side: s.side, elo: s.elo })
{
  let convictions = 0
  let escalations = 0
  let maxChunkZ = -Infinity
  let nWindows = 0
  for (let i = 0; i + K <= honestSides.length; i += K) {
    const v = J.windowVerdict(honestSides.slice(i, i + K).map(entryOf), A)
    nWindows++
    if (v.convicted) convictions++
    if (v.escalate) escalations++
    if (v.zMicro > maxChunkZ) maxChunkZ = v.zMicro
  }
  eq(convictions, 0, `ZERO convictions over ${nWindows} honest ${K}-game windows`)
  eq(escalations, 0, `ZERO escalations over ${nWindows} honest ${K}-game windows`)
  // trailing-K scan (the deterministic trigger's exact geometry)
  let maxZ = -Infinity
  for (let i = K - 1; i < honestSides.length; i++) {
    const { zMicro } = J.aggregateZMicro(honestSides.slice(i - K + 1, i + 1).map(entryOf), A)
    if (zMicro > maxZ) maxZ = zMicro
  }
  const games = honestSides.map((s, i) => ({ game: `${s.rec.game}#${s.side}`, side: s.side, elo: s.elo }))
  const records = new Map(honestSides.map((s) => [`${s.rec.game}#${s.side}`, s.rec]))
  const esc = J.escalationDue(games, records, A)
  eq(esc.due, false, 'escalationDue over the FULL honest stream: never fires')
  console.log(
    `  · max honest trailing-${K} z = ${(maxZ / 1e6).toFixed(3)}σ, max chunk z = ${(maxChunkZ / 1e6).toFixed(3)}σ — ` +
      `margin to escalation (3.0): ${((J.PARAMS_A5.zEscalateMicro - maxZ) / 1e6).toFixed(3)}σ, ` +
      `to conviction (5.0): ${((J.PARAMS_A5.zThresholdMicro - maxZ) / 1e6).toFixed(3)}σ`,
  )
  ok(maxZ < J.PARAMS_A5.zEscalateMicro, `max honest trailing-K z (${(maxZ / 1e6).toFixed(3)}σ) stays under the escalation trigger`)
}
{
  // split-half: anchors refit on even-indexed games, scan odd-indexed games
  const keys = [...new Set(honestSides.map((s) => s.rec.game))].sort()
  const even = new Set(keys.filter((_, i) => i % 2 === 0))
  const fitB = fitAnchors(honestSides.filter((s) => even.has(s.rec.game)))
  const hold = honestSides.filter((s) => !even.has(s.rec.game))
  let maxZ = -Infinity
  for (let i = K - 1; i < hold.length; i++) {
    const { zMicro } = J.aggregateZMicro(hold.slice(i - K + 1, i + 1).map(entryOf), fitB)
    if (zMicro > maxZ) maxZ = zMicro
  }
  console.log(`  · split-half: held-out max trailing-${K} z = ${(maxZ / 1e6).toFixed(3)}σ over ${hold.length} sides`)
  ok(maxZ < J.PARAMS_A5.zEscalateMicro, 'split-half held-out max z also stays under the escalation trigger (in-sample bias bounded)')
}
{
  // ── A5-09 — LONGITUDINAL single-account holdout (the PRODUCTION trigger
  // geometry). The §3 proof above is CROSS-SECTIONAL: every trailing-K window
  // is 30 DIFFERENT corpus bots at different bands, so it structurally cannot
  // exhibit ONE account's temporal stream — exactly what the deployed
  // escalationDue evaluates (tier2.ts: ONE (root, ladder)'s trailing reganK
  // games). Here we assemble ONE honest account of a fixed TRUE strength T from
  // the COMMITTED T-band honest sides (no re-judging) and run the REAL
  // escalationDue over a CLIMBING display-rating schedule whose rating LAGS
  // true strength — a fresh/improving honest account. This validates the A5-02
  // RD-aware fix INSIDE the calibration proof (A5-02's residual deferred exactly
  // this): scored at the lagging display rating (rdMicro absent = the pre-A5-02
  // point-estimate path) the honest climb FALSELY escalates; scored at the RD
  // upper-confidence effElo (rdMicro present = the deployed path) the SAME
  // stream never fires.
  //
  // The account is honest ⇒ mean-zero at its TRUE band by construction (the
  // committed anchors ARE that band's PAV means). The climb is COUPLED so the
  // fold RD tracks the lag: display elo = T − 2·RD with RD decaying from the 350
  // fresh seed to the settled floor 30, so effElo = elo + RD_CONF_MUL·RD ≡ T at
  // every game (the A5-02 invariant for an honest improver) while the DISPLAYED
  // rating lags T by up to 700 Elo early in the climb.
  const T = 2700 // the top honest band = the account's fixed TRUE strength
  const trueSides = honestSides.filter((s) => s.elo === T)
  ok(trueSides.length >= 1, `longitudinal: corpus carries true-${T} honest sides (${trueSides.length})`)
  const N = 3 * K // 90 games — many trailing-K windows spanning the whole climb
  const rdOf = (i) => 350 - Math.floor(((350 - 30) * i) / (N - 1)) // 350 → 30, integer
  const acct = []
  for (let i = 0; i < N; i++) {
    const s = trueSides[i % trueSides.length] // committed T-band signals, cycled
    const rd = rdOf(i)
    acct.push({ rec: s.rec, side: s.side, elo: T - 2 * rd, rdMicro: rd * 1_000_000 })
  }
  const legacyEntry = (e) => ({ rec: e.rec, side: e.side, elo: e.elo }) // rdMicro absent
  const rdEntry = (e) => ({ rec: e.rec, side: e.side, elo: e.elo, rdMicro: e.rdMicro })
  // Max trailing-K z under each scoring over the whole stream — escalationDue's
  // exact geometry (it fires at the earliest trailing-K window ≥ 3.0σ).
  let maxLegacy = -Infinity
  let maxRd = -Infinity
  for (let i = K - 1; i < acct.length; i++) {
    maxLegacy = Math.max(maxLegacy, J.aggregateZMicro(acct.slice(i - K + 1, i + 1).map(legacyEntry), A).zMicro)
    maxRd = Math.max(maxRd, J.aggregateZMicro(acct.slice(i - K + 1, i + 1).map(rdEntry), A).zMicro)
  }
  const key = (e, i) => `${e.rec.game}#${e.side}#${i}` // one account, cycled recs ⇒ unique keys
  const gamesRd = acct.map((e, i) => ({ game: key(e, i), side: e.side, elo: e.elo, rdMicro: e.rdMicro }))
  const gamesLegacy = acct.map((e, i) => ({ game: key(e, i), side: e.side, elo: e.elo }))
  const records = new Map(acct.map((e, i) => [key(e, i), e.rec]))
  const escLegacy = J.escalationDue(gamesLegacy, records, A)
  const escRd = J.escalationDue(gamesRd, records, A)
  console.log(
    `  · longitudinal true-${T} honest climb (${N} games, display lags ${2 * rdOf(0)}→${2 * rdOf(N - 1)} Elo as RD ${rdOf(0)}→${rdOf(N - 1)}): ` +
      `legacy max trailing-${K} z = ${(maxLegacy / 1e6).toFixed(3)}σ (escalates), RD-aware max = ${(maxRd / 1e6).toFixed(3)}σ`,
  )
  ok(
    escLegacy.due,
    `longitudinal legacy (rdMicro absent): honest true-${T} climb FALSELY escalates at the lagging display rating ` +
      `(z ${(maxLegacy / 1e6).toFixed(3)}σ) — the A5-02 false positive the cross-sectional §3 proof structurally cannot exhibit`,
  )
  eq(
    escRd.due,
    false,
    `longitudinal RD-aware (A5-02 effElo): the SAME honest climb NEVER escalates ` +
      `(max trailing-${K} z ${(maxRd / 1e6).toFixed(3)}σ < 3.0σ) — the display-rating-lag FPR is closed`,
  )
  // RESIDUAL (A5-09): this holdout closes the display-rating-lag longitudinal FPR
  // (A5-02). The finding's OTHER mode — a SETTLED account whose per-game move
  // quality persistently sits d·σ off its true-band mean (a within-band style
  // residual the RD fix cannot compensate once RD floors) — is NOT exhibited
  // here: the committed corpus has a single play-model per band, so it carries
  // ZERO within-band variance. A persistent d ≥ 0.55σ (= 3.0/√K) reaches the
  // escalation trigger over one K-window; proving THAT mode safe needs a
  // heterogeneous corpus (engine regen; drifts anchors/goldens) or per-player
  // baselining in tier2.ts (cross-lane) — see the review Residual.
}

// ---- 4. cheater convictions ---------------------------------------------------
section('seeded cheaters: convicted within ONE reganK window')
function familyProof(family, mustConvict) {
  const sides = sidesOf(family)
  const entries = sides.map(entryOf)
  const v = J.windowVerdict(entries.slice(0, Math.min(entries.length, 2 * K - 1)), A)
  console.log(
    `  · ${family}: ${entries.length} games, window z = ${(v.zMicro / 1e6).toFixed(3)}σ ` +
      `(scored ${v.scoredGames}) convicted=${v.convicted} escalate=${v.escalate}`,
  )
  if (mustConvict) {
    ok(v.convicted, `${family}: window CONVICTS (z ${(v.zMicro / 1e6).toFixed(2)}σ ≥ 5.0)`)
    let toConvict = null
    let toEscalate = null
    for (let n = 1; n <= entries.length; n++) {
      const p = J.windowVerdict(entries.slice(0, n), A)
      if (toEscalate === null && p.escalate) toEscalate = n
      if (p.convicted) {
        toConvict = n
        break
      }
    }
    ok(toConvict !== null && toConvict <= K, `${family}: games-to-conviction ${toConvict} ≤ K (${K}); escalation at game ${toEscalate}`)
    // the deterministic trigger fires inside the window
    if (entries.length >= K) {
      const games = sides.map((s) => ({ game: s.rec.game, side: s.side, elo: s.elo }))
      const records = new Map(sides.map((s) => [s.rec.game, s.rec]))
      const esc = J.escalationDue(games, records, A)
      ok(esc.due, `${family}: the deterministic escalationDue trigger fires (z ${(esc.zMicro / 1e6).toFixed(2)}σ at index ${esc.atIndex})`)
    } else {
      ok(J.windowVerdict(entries, A).escalate, `${family}: escalation condition met on the (short) family window`)
    }
  }
  return { v, entries, sides }
}
familyProof('full', true)
familyProof('half', true)

// ---- 5. threshold-ε -----------------------------------------------------------
section('threshold-ε: metered assistance sits under the conviction line')
const th = familyProof('thresh', false)
ok(th.v.zMicro < J.PARAMS_A5.zThresholdMicro, `thresh window z ${(th.v.zMicro / 1e6).toFixed(3)}σ < conviction (5.0) — escalate-not-convict or below`)
console.log(
  `  · thresh z sits ${th.v.zMicro >= J.PARAMS_A5.zEscalateMicro ? 'INSIDE the escalate band [3.0, 5.0)' : `below escalation (Δ ${((J.PARAMS_A5.zEscalateMicro - th.v.zMicro) / 1e6).toFixed(3)}σ)`}` +
    ` at assist p = ${(th.sides[0].r.assistProbMicro / 1e6).toFixed(4)}`,
)

// ---- 5b. J7 cross-window lifetime accumulation --------------------------------
section('J7 lifetime accumulation: sustained metering convicts, honest never')
{
  // Chain order = corpus append order (the order the metered ladder's games
  // were generated) — thresh rows only, subject side, scored games.
  const chain = rows
    .filter((r) => r.family === 'thresh' && r.rec[r.subject].scored >= 1)
    .map((r) => ({ rec: r.rec, side: r.subject, elo: r.subject === 'w' ? r.whiteElo : r.blackElo }))
  const nW = Math.floor(chain.length / K)
  ok(nW >= 4, `thresh chain closes ≥ 4 K-windows (${chain.length} games ⇒ ${nW} windows)`)
  const wz = []
  for (let w = 0; w < nW; w++) {
    wz.push(J.windowVerdict(chain.slice(w * K, (w + 1) * K).map(entryOf), A).zMicro)
  }
  const subEsc = wz.filter((z) => z < J.PARAMS_A5.zEscalateMicro).length
  const maxW = Math.max(...wz)
  console.log(
    `  · ${nW} closed ${K}-game windows, per-window z: [${wz.map((z) => (z / 1e6).toFixed(2)).join(', ')}]σ\n` +
      `  · mean ${(wz.reduce((a, b) => a + b, 0) / nW / 1e6).toFixed(3)}σ (metering target 2.6σ), ` +
      `${subEsc}/${nW} sub-escalation, max ${(maxW / 1e6).toFixed(3)}σ`,
  )
  ok(maxW < J.PARAMS_A5.zThresholdMicro, `NO single window convicts (max ${(maxW / 1e6).toFixed(2)}σ < 5.0) — the J6 evasion holds per-window`)
  ok(wz.reduce((a, b) => a + b, 0) / nW < J.PARAMS_A5.zEscalateMicro, 'mean window z stays sub-escalation (the metering premise)')
  ok(subEsc >= nW / 2, `most windows individually sub-escalation (${subEsc}/${nW}; sampling noise pokes a few over)`)
  // The lifetime trajectory — evaluated at every window close, as the trigger is.
  let escW = null
  let convW = null
  const traj = []
  for (let w = 1; w <= nW; w++) {
    const lv = J.lifetimeVerdict(wz.slice(0, w))
    traj.push(lv.zLifeMicro)
    if (escW === null && lv.escalate) escW = w
    if (convW === null && lv.convicted) convW = w
  }
  console.log(
    `  · z_life trajectory: [${traj.map((z) => (z / 1e6).toFixed(2)).join(', ')}]σ\n` +
      `  · REALIZED CROSSINGS: escalation at window ${escW}, CONVICTION at window ${convW} ` +
      `(${convW === null ? '—' : convW * K} metered games; ideal 2.6σ/window ⇒ ~2 and ~4)`,
  )
  ok(escW !== null && escW <= 5, `lifetime ESCALATES within a few windows (window ${escW} ≤ 5)`)
  ok(convW !== null, `lifetime CONVICTS at window ${convW} — sustained metering cannot stay under the line (§7a closed)`)
  ok(escW !== null && convW !== null && escW <= convW, 'escalation precedes conviction')
  ok(J.lifetimeVerdict(wz).convicted, 'the full closed-window set stands convicted')
  // Trigger integration on the real streams: the thresh chain must be DUE
  // (trailing-K or lifetime — both are the one deterministic condition now);
  // the honest stream with its own closed windows stays quiet.
  const thGames = chain.map((e, i) => ({ game: `${e.rec.game}#${i}`, side: e.side, elo: e.elo }))
  const thRecs = new Map(chain.map((e, i) => [`${e.rec.game}#${i}`, e.rec]))
  const escTh = J.escalationDue(thGames, thRecs, A, wz)
  ok(escTh.due, `escalationDue fires on the metered chain (${escTh.lifetime ? `lifetime W=${escTh.lifetime.windows}` : `trailing-K at index ${escTh.atIndex}`})`)
  // Honest false-positive guard: closed windows + lifetime trajectory.
  const hN = Math.floor(honestSides.length / K)
  const hwz = []
  for (let w = 0; w < hN; w++) {
    hwz.push(J.windowVerdict(honestSides.slice(w * K, (w + 1) * K).map(entryOf), A).zMicro)
  }
  let hMax = -Infinity
  const hTraj = []
  for (let w = 1; w <= hN; w++) {
    const lv = J.lifetimeVerdict(hwz.slice(0, w))
    hTraj.push(lv.zLifeMicro)
    if (lv.zLifeMicro > hMax) hMax = lv.zLifeMicro
  }
  console.log(
    `  · honest lifetime over ${hN} windows: [${hTraj.map((z) => (z / 1e6).toFixed(2)).join(', ')}]σ\n` +
      `  · max honest z_life ${(hMax / 1e6).toFixed(3)}σ — margin ${((2_000_000 - hMax) / 1e6).toFixed(3)}σ to the 2σ guard, ` +
      `${((J.PARAMS_A5.zEscalateMicro - hMax) / 1e6).toFixed(3)}σ to escalation`,
  )
  ok(
    hMax < 2_000_000,
    `honest lifetime never drifts above 2σ (max ${(hMax / 1e6).toFixed(3)}σ) — accumulation FP guard; if this trips: STOP, report to the lead, do NOT tune`,
  )
  const escHonest = J.escalationDue(
    honestSides.map((s, i) => ({ game: `${s.rec.game}#${s.side}`, side: s.side, elo: s.elo })),
    new Map(honestSides.map((s) => [`${s.rec.game}#${s.side}`, s.rec])),
    A,
    hwz,
  )
  eq(escHonest.due, false, 'escalationDue with lifetime evidence: still NEVER fires on the honest stream')
}

// ---- 6. the §7(a) empty-margin number -----------------------------------------
section('§7(a) empty margin: Elo gain/game at max-undetectable assistance')
{
  const G = J.glicko
  // Settled true-strength state: display 1500, RD 60 (settled), vol 0.06 —
  // opponents identical (the thresh schedule pairs 1500 vs 1500).
  const settled = { ratingMicro: 1_500_000_000, rdMicro: 60_000_000, volMicro: 60_000 }
  const foldRun = (scores) => {
    let p = { ...settled }
    for (const s of scores) {
      p = G.glickoUpdateMicro(p, [{ ratingMicro: 1_500_000_000, rdMicro: 60_000_000, score: s }])
    }
    return p
  }
  const threshScores = th.sides.map((s) => (s.side === 'w' ? s.r.resultWhite2 : 2 - s.r.resultWhite2) / 2)
  const n = threshScores.length
  const scoreRate = mean(threshScores)
  const pTh = foldRun(threshScores)
  const gainPerGame = (pTh.ratingMicro - settled.ratingMicro) / n / 1e6
  // Baseline: an exactly-50% alternating sequence of the same length.
  const base = foldRun(Array.from({ length: n }, (_, i) => (i % 2 === 0 ? 1 : 0)))
  const basePerGame = (base.ratingMicro - settled.ratingMicro) / n / 1e6
  // Honest 1500 self-play (the true-strength baseline score) for context.
  const honest1500 = rows.filter((r) => r.family === 'honest' && r.whiteElo === 1500 && r.blackElo === 1500)
  console.log(
    `  · thresh: ${n} games vs 1500, score rate ${scoreRate.toFixed(3)} (honest baseline 0.500, ` +
      `${honest1500.length} honest 1500v1500 games on file)`,
  )
  console.log(
    `  · deterministic glicko fold from settled (1500, RD 60): ${(pTh.ratingMicro / 1e6).toFixed(1)} after ${n} games ` +
      `⇒ ${gainPerGame >= 0 ? '+' : ''}${gainPerGame.toFixed(2)} Elo/game (50%-alternating baseline ${basePerGame >= 0 ? '+' : ''}${basePerGame.toFixed(2)})`,
  )
  console.log(
    `  · THE §7(a) NUMBER: max-undetectable assistance buys ≈ ${(gainPerGame - basePerGame).toFixed(2)} Elo/game over the true-strength baseline ` +
      `(score edge ${(scoreRate - 0.5) >= 0 ? '+' : ''}${(scoreRate - 0.5).toFixed(3)}/game, binomial ±${(0.5 / Math.sqrt(n)).toFixed(3)})`,
  )
  ok(Number.isFinite(gainPerGame), 'empty-margin fold is finite and deterministic')
  ok(
    Math.abs(gainPerGame - basePerGame) < 15,
    `empty-margin sanity: |gain − baseline| = ${Math.abs(gainPerGame - basePerGame).toFixed(2)} Elo/game < 15 (a blown bound here is a params/threshold finding — STOP for the lead)`,
  )
}

// ---- A5-29: canonical judging-surface receipt (engine-free, ALL families) -----
// The §7 engine receipt routes ONE local honest re-judge through the canonical
// transcriptToJudgePositions builder (A5-01) — but §7 is skipped under CI, so on
// its own no CI test can detect a judged-surface / encoding divergence between
// PRODUCERS (the in-repo gen-judge-corpus fenBefore+TAIL vs gen-cheater-corpus
// no-tail fork, or a future 'position fen START moves …' encoder). Here the SAME
// canonical builder runs over EVERY corpus row of EVERY family, engine-free, and
// must reproduce the exact surface the corpus was measured on: nPlies positions,
// ply i, bare FEN == fens[i], NO moves/path field, contiguous from 0, no tail. A
// producer that judged a ply subset, appended a tail, or used the moves-path
// encoding diverges HERE — under CI, across the conviction-bearing families too,
// not just one local honest row.
section('canonical judging surface: transcriptToJudgePositions reproduces every corpus row (A5-29)')
{
  ok(typeof J.transcriptToJudgePositions === 'function', 'transcriptToJudgePositions exported from the judge barrel (A5-01)')
  let bad = 0
  const per = { honest: 0, full: 0, half: 0, thresh: 0 }
  for (const r of rows) {
    let pos
    try {
      pos = J.transcriptToJudgePositions(
        r.moves.map((m, i) => ({ ply: i, move: m })),
        (i) => r.fens[i],
      )
    } catch {
      bad++
      continue
    }
    const good =
      pos.length === r.nPlies && pos.every((p, i) => p.ply === i && p.fen === r.fens[i] && p.moves === undefined)
    if (good) per[r.family] = (per[r.family] ?? 0) + 1
    else bad++
  }
  eq(bad, 0, `A5-29: canonical builder reproduces the judged surface of all ${rows.length} rows (every ply, bare-FEN, no tail)`)
  ok(
    per.honest >= 1 && per.full >= 1 && per.half >= 1 && per.thresh >= 1,
    `A5-29: all four families receipt-verified through the canonical builder (honest ${per.honest}, full ${per.full}, half ${per.half}, thresh ${per.thresh}) — not one honest row`,
  )
  // Non-vacuity: the builder emits EXACTLY moves.length bare-FEN positions, so a
  // tail-carrying producer (fens length nPlies+1) or a subset producer cannot
  // round-trip through it — the receipt is not self-satisfying.
  const r0 = rows[0]
  const tailFens = [...r0.fens, r0.fens[r0.nPlies - 1]]
  const tail = J.transcriptToJudgePositions(
    r0.moves.map((m, i) => ({ ply: i, move: m })),
    (i) => tailFens[i],
  )
  ok(
    tail.length === r0.nPlies && tailFens.length === r0.nPlies + 1,
    `A5-29 non-vacuity: builder drops any tail — a nPlies+1 producer surface (${tailFens.length}) is not reproduced (${tail.length} == nPlies)`,
  )
}

// ---- 7. engine receipt (LOCAL-ONLY, test-judge-node convention) ---------------
if (process.env.CI) {
  section('engine receipt: SKIP under CI (engine-heavy suites are local-only)')
} else if (!existsSync(ENGINE_WASM)) {
  section('engine receipt: SKIP (pinned judge wasm not installed)')
} else {
  section('engine receipt: re-judge one stored game ⇒ byte-identical Tier1Record')
  const r0 = rows.find((r) => r.family === 'honest')
  const eng = await J.adapter.newNodeJudgeEngine({ enginePath: ENGINE_JS, wasmPath: ENGINE_WASM })
  try {
    // Cross-artifact receipt goes through the CANONICAL builder (A5-01), not
    // a re-statement of the corpus generator's private convention — same
    // surface, same bits.
    const moves = r0.moves.map((m, i) => ({ ply: i, move: m, clockMs: { w: 0, b: 0 } }))
    const positions = J.transcriptToJudgePositions(moves, (i) => r0.fens[i])
    const out = await J.judgeGame(eng, positions, J.judgeConfigForTier(1))
    const rec = J.tier1Record(r0.gameKey, 'calib', out, moves, 'w')
    eq(J.tier1Digest(rec), J.tier1Digest(r0.rec), `re-judged ${r0.gameKey} (${r0.nPlies} plies): Tier1Record digest reproduces bit-for-bit`)
  } finally {
    await eng.close()
  }
}

console.log(
  `\n${failures ? `❌ ${failures} FAILED — ` : 'ALL GREEN — '}${passed} assertions${failures ? `, ${failures} failures` : ''}`,
)
process.exit(failures ? 1 : 0)
